"""
Hello World HTTP handler — Python compiled to WASM via componentize-py.

componentize-py generates Python bindings from the WIT interface and embeds
CPython into the resulting .wasm component.  The module must export a class
whose name matches the world's exported interface: IncomingHandler.

Build:
    componentize-py -d wit -w proxy componentize app -o hello-py-raw.wasm

Run:
    wasmtime serve hello-py-raw.wasm --addr 127.0.0.1:5032
"""

import json
import time

# These imports come from the bindings auto-generated by componentize-py.
# They mirror the wasi:http/types WIT resource types.
from proxy.exports.wasi.http.incoming_handler import IncomingHandler
from proxy.imports.wasi.http.types import (
    Fields,
    OutgoingBody,
    OutgoingResponse,
    ResponseOutparam,
)


class IncomingHandlerImpl(IncomingHandler):
    def handle(self, request, response_out: ResponseOutparam) -> None:
        body = json.dumps(
            {
                "message": "Hello World",
                "timestamp": time.time(),
            }
        ).encode()

        headers = Fields.from_list([(b"content-type", b"application/json")])
        response = OutgoingResponse(headers)
        response.set_status_code(200)

        outgoing_body = response.body()
        stream = outgoing_body.write()
        stream.blocking_write_and_flush(body)
        del stream

        OutgoingBody.finish(outgoing_body, None)
        ResponseOutparam.set(response_out, response)
